// Compose newsletter payload. Returns one item with array of subscriber emails + HTML body.
const pkgRows = $('Top 3 packages by savings').all();
const subRows = $('Active subscribers').all();

const pkgs = [];
for (const r of pkgRows) {
  if (r.json?.document) {
    const f = r.json.document.fields;
    pkgs.push({
      city: f.destination?.mapValue?.fields?.city?.stringValue || 'Unknown',
      country: f.destination?.mapValue?.fields?.country?.stringValue || '',
      total: parseInt(f.pricing?.mapValue?.fields?.total?.integerValue || '0'),
      agency: parseInt(f.pricing?.mapValue?.fields?.agencyReference?.integerValue || '0'),
      pct: parseInt(f.pricing?.mapValue?.fields?.savingsPercent?.integerValue || '0')
    });
  }
}

const emails = [];
for (const r of subRows) {
  if (r.json?.document) {
    const e = r.json.document.fields?.email?.stringValue;
    if (e) emails.push(e);
  }
}

const rowsHtml = pkgs.map(p => `
  <tr><td style="padding:16px 0;border-bottom:1px solid #DCD1B3;">
    <div style="font-family:Georgia,serif;font-size:22px;color:#0A0D11;margin-bottom:6px;">${p.city}, ${p.country}</div>
    <div style="font-family:monospace;font-size:14px;color:#6E6453;">€${p.total} <span style="color:#6B1A25;">(${p.pct}% off · agencija €${p.agency})</span></div>
  </td></tr>
`).join('');

const html = `
<!doctype html><html><body style="margin:0;background:#F5EFE0;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;margin:0 auto;padding:32px 24px;">
<tr><td style="text-align:center;padding-bottom:24px;">
<div style="font-family:Georgia,serif;font-style:italic;font-size:32px;color:#0A0D11;">letto<span style="font-style:normal;font-size:11px;color:#A17433;letter-spacing:0.1em;">.LIVE</span></div>
</td></tr>
<tr><td style="font-family:Georgia,serif;font-size:18px;line-height:1.5;color:#0A0D11;padding-bottom:16px;">This week's <em style="color:#A17433;">3 best</em> packages — already at &gt;30% below the median.</td></tr>
<tr><td><table width="100%" cellpadding="0" cellspacing="0">${rowsHtml}</table></td></tr>
<tr><td style="padding-top:24px;text-align:center;">
<a href="https://letto.live/#pricing" style="display:inline-block;background:#A17433;color:#F5E9D0;padding:14px 28px;border-radius:999px;text-decoration:none;font-weight:500;">Unlock full details — €19/3mo</a>
</td></tr>
<tr><td style="padding-top:32px;font-size:11px;color:#6E6453;text-align:center;line-height:1.5;">LETTO.LIVE · SIAL Consulting · Slovenia<br><a href="https://letto.live" style="color:#A17433;">letto.live</a> · <a href="https://letto.live/#unsub" style="color:#A17433;">unsubscribe</a></td></tr>
</table></body></html>
`;

return [{ json: { emails, html, packageCount: pkgs.length, subject: `LETTO weekly · 3 packages, top ${pkgs[0]?.pct || 0}% off` } }];

